const char* getNamedResource (const char* resourceNameUTF8, int& numBytes)
{
    unsigned int hash = 0;

    if (resourceNameUTF8 != nullptr)
        while (*resourceNameUTF8 != 0)
            hash = 31 * hash + (unsigned int) *resourceNameUTF8++;

    switch (hash)
    {
        case 0xa6d8b27a:  numBytes = 1227; return Loop_h_bak;
        case 0x2402c164:  numBytes = 229; return MenuManager_h_bak;
        case 0xf76808d1:  numBytes = 80403; return PluginEditor_cpp_bak;
        case 0xb2fb8156:  numBytes = 11821; return PluginEditor_h_bak;
        case 0xd70e79b0:  numBytes = 118887; return PluginProcessor_cpp_bak;
        case 0x24f69df5:  numBytes = 6678; return PluginProcessor_h_bak;
        case 0x52d0f05c:  numBytes = 28363; return Track_cpp_bak;
        default: break;
    }

    numBytes = 0;
    return nullptr;
}

